import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"Security","description":"The real security posture of Foldergram, including admin/viewer/public access control, mutation trust checks, and local-only caveats.","frontmatter":{"title":"Security","description":"The real security posture of Foldergram, including admin/viewer/public access control, mutation trust checks, and local-only caveats."},"headers":[],"relativePath":"security.md","filePath":"security.md","lastUpdated":1775244546000}'),r={name:"security.md"};function l(s,e,n,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><p>Foldergram is built for local-only and self-hosted browsing. Its security model is intentionally narrow even though it now supports an optional admin/viewer/public access gate for homelab and LAN use.</p><h2 id="what-foldergram-assumes" tabindex="-1">What Foldergram assumes <a class="header-anchor" href="#what-foldergram-assumes" aria-label="Permalink to &quot;What Foldergram assumes&quot;">​</a></h2><ul><li>you run it on your own machine or behind a trusted local-network or reverse-proxy setup</li><li>the app is not exposed directly to the public internet without additional protection</li><li>the built-in auth story is a small role-based password gate, not a multi-user account system</li></ul><h2 id="password-protection" tabindex="-1">Password protection <a class="header-anchor" href="#password-protection" aria-label="Permalink to &quot;Password protection&quot;">​</a></h2><p>Foldergram can optionally protect the library from the Settings page with:</p><ul><li>an <code>admin</code> password for full access</li><li>an optional separate <code>viewer</code> password for browse-only access</li><li>an optional <code>public</code> viewer mode for anonymous browsing with local favorites</li></ul><p>When enabled:</p><ul><li>Foldergram stores one-way password hashes, salts, and session metadata in SQLite <code>app_settings</code></li><li>the browser unlocks access with a signed <code>HttpOnly</code> session cookie</li><li>the session payload carries the current role (<code>admin</code> or <code>viewer</code>)</li><li><code>/api</code> routes require that session, except for <code>GET /api/health</code>, <code>GET /api/auth/status</code>, <code>POST /api/auth/login</code>, <code>POST /api/auth/unlock-admin</code>, and <code>POST /api/auth/logout</code></li><li>generated media under <code>/thumbnails</code> and <code>/previews</code> also require that session unless public viewer mode is enabled</li><li>in <code>viewer_access_mode=public</code>, safe read routes and generated media can be browsed anonymously</li><li>anonymous public favorites stay in the browser and never write into SQLite likes</li><li>authenticated API and media responses are marked <code>Cache-Control: no-store</code> and <code>Vary: Cookie</code></li><li>the production service worker skips caching protected thumbnail and preview responses</li><li>admin-only routes reject <code>viewer</code> and <code>anonymous</code> sessions with <code>403</code> or <code>401</code> depending on auth state</li></ul><p>Changing either stored password or the viewer-access mode rotates the session version, which invalidates older sessions. Disabling password protection clears the stored auth settings.</p><h2 id="mutation-protection" tabindex="-1">Mutation protection <a class="header-anchor" href="#mutation-protection" aria-label="Permalink to &quot;Mutation protection&quot;">​</a></h2><p>All mutating API routes pass through <code>requireTrustedMutationRequest</code>.</p><p>That middleware does two things:</p><ol><li>Requires <code>x-foldergram-intent: 1</code></li><li>Rejects non-loopback <code>Origin</code> or <code>Referer</code> values when those headers are present</li></ol><p>Allowed hostnames are:</p><ul><li><code>localhost</code></li><li><code>127.0.0.1</code></li><li><code>::1</code></li></ul><p>Allowed ports are:</p><ul><li><code>DEV_SERVER_PORT</code> and the reserved <code>DEV_CLIENT_PORT</code> through <code>DEV_CLIENT_PORT + 3</code> range in development or test</li><li><code>SERVER_PORT</code> in production, with loopback origins or the exact host that served the app accepted for browser mutations</li><li>explicit extra origins can be allowed through <code>CSRF_TRUSTED_ORIGINS</code></li></ul><h2 id="what-this-protects-against" tabindex="-1">What this protects against <a class="header-anchor" href="#what-this-protects-against" aria-label="Permalink to &quot;What this protects against&quot;">​</a></h2><p>With password protection enabled, this design helps reduce opportunistic browsing of the library from other machines on the same network.</p><p>Separately, the mutation checks help reduce accidental or cross-site browser-triggered mutations from untrusted origins.</p><p>It is especially relevant for:</p><ul><li>feed and folder reads when password protection is enabled</li><li>generated thumbnails and previews when password protection is enabled and public mode is off</li><li>delete actions</li><li>like toggles</li><li>manual rescans</li><li>rebuild operations</li><li>Settings-only auth changes</li></ul><h2 id="path-confinement" tabindex="-1">Path confinement <a class="header-anchor" href="#path-confinement" aria-label="Permalink to &quot;Path confinement&quot;">​</a></h2><p>Foldergram does not serve arbitrary filesystem paths from the client.</p><h3 id="original-file-serving" tabindex="-1">Original-file serving <a class="header-anchor" href="#original-file-serving" aria-label="Permalink to &quot;Original-file serving&quot;">​</a></h3><p><code>GET /api/originals/:id</code>:</p><ul><li>looks up the post by numeric ID</li><li>resolves the stored absolute path</li><li>confirms that path is still within <code>GALLERY_ROOT</code></li><li>confirms the file still exists</li></ul><h3 id="delete-actions" tabindex="-1">Delete actions <a class="header-anchor" href="#delete-actions" aria-label="Permalink to &quot;Delete actions&quot;">​</a></h3><p>Delete flows resolve target files and directories inside configured roots before removing them. If a stored path falls outside the expected root, the operation throws instead of deleting blindly.</p><h2 id="storage-availability-behavior" tabindex="-1">Storage availability behavior <a class="header-anchor" href="#storage-availability-behavior" aria-label="Permalink to &quot;Storage availability behavior&quot;">​</a></h2><p>On startup, Foldergram checks:</p><ul><li>gallery directory</li><li>thumbnails directory</li><li>previews directory</li><li>database directory</li></ul><p>If the database directory is unavailable, it falls back to an in-memory database. If the gallery or derivative directories are unavailable, the library is marked unavailable and the UI receives explicit storage-state information.</p><p>This is a resilience measure, not a security feature.</p><h2 id="rate-limiting" tabindex="-1">Rate limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate limiting&quot;">​</a></h2><p>Foldergram includes small in-memory rate limiters for:</p><ul><li>authentication attempts</li><li>admin mutation routes such as rescan and rebuild operations</li></ul><p>These limiters are process-local and intentionally simple. They are useful for basic abuse reduction, not for hardened distributed deployments.</p><h2 id="important-limitations" tabindex="-1">Important limitations <a class="header-anchor" href="#important-limitations" aria-label="Permalink to &quot;Important limitations&quot;">​</a></h2><p>Foldergram does <strong>not</strong> currently provide:</p><ul><li>multi-user authentication</li><li>per-user authorization</li><li>TLS termination</li><li>audit logging</li><li>hardened remote deployment defaults</li><li>external identity provider integration</li><li>per-user isolation</li></ul><h2 id="practical-advice" tabindex="-1">Practical advice <a class="header-anchor" href="#practical-advice" aria-label="Permalink to &quot;Practical advice&quot;">​</a></h2><p>Use Foldergram like a local app:</p><ul><li>use strong, different admin and viewer passwords if you expose it on a homelab or LAN</li><li>remember that public viewer mode exposes the library to anyone who can reach the app</li><li>keep it on loopback unless you know exactly how you are proxying and protecting it</li><li>terminate HTTPS upstream if the app is reachable off-box</li><li>remember that on plain HTTP, both the password and session cookie are visible to anyone who can sniff that local network traffic</li><li>do not assume the password layer and mutation checks are a full internet-facing security boundary</li><li>treat delete actions as destructive and permanent</li></ul><h2 id="a-precise-caveat-about-headers" tabindex="-1">A precise caveat about headers <a class="header-anchor" href="#a-precise-caveat-about-headers" aria-label="Permalink to &quot;A precise caveat about headers&quot;">​</a></h2><p>If a mutating request omits both <code>Origin</code> and <code>Referer</code>, the middleware still accepts it as long as <code>x-foldergram-intent: 1</code> is present. That is acceptable for the current local-only model, but it is one reason these checks should not be described as a full remote-hardening story.</p><h2 id="what-foldergram-does-not-try-to-be" tabindex="-1">What Foldergram does not try to be <a class="header-anchor" href="#what-foldergram-does-not-try-to-be" aria-label="Permalink to &quot;What Foldergram does not try to be&quot;">​</a></h2><p>Foldergram is not attempting to be:</p><ul><li>a cloud photo product</li><li>a multi-user NAS portal</li><li>a public media server with account management</li><li>a zero-trust network service</li></ul><p>The implementation is much closer to a private local gallery with a browser UI.</p>',51)])])}const m=a(r,[["render",l]]);export{p as __pageData,m as default};
